/**
 * Organization Module Public API
 *
 * Centralized exports for the Organization module.
 * Import from this file when using organization module functionality
 * from other parts of the application.
 *
 * @module modules/_core/organization
 *
 * @example
 * ```typescript
 * import {
 *   OrganizationModule,
 *   OrganizationService,
 *   organizationRoutes,
 *   type Organization,
 *   type CreateOrganizationRequest,
 * } from '@/modules/_core/organization';
 * ```
 */

// -----------------------------------------------------------------------------
// Module Definition
// -----------------------------------------------------------------------------

export { OrganizationModule, default } from '@/modules/_core/organization/organization.module';
export type {
  OrganizationModuleContext,
  OrganizationModuleHooks,
} from '@/modules/_core/organization/organization.module';

// -----------------------------------------------------------------------------
// Service
// -----------------------------------------------------------------------------

export { OrganizationService } from '@/modules/_core/organization/organization.service';

// -----------------------------------------------------------------------------
// Repository
// -----------------------------------------------------------------------------

export { OrganizationRepository } from '@/modules/_core/organization/organization.repository';
export type {
  PaginatedResult,
  CreateOrganizationData,
  UpdateOrganizationData,
} from '@/modules/_core/organization/organization.repository';

// -----------------------------------------------------------------------------
// Controller
// -----------------------------------------------------------------------------

export { OrganizationController } from '@/modules/_core/organization/organization.controller';

// -----------------------------------------------------------------------------
// Routes
// -----------------------------------------------------------------------------

export {
  organizationRoutes,
  buildOrganizationApiPath,
  buildOrganizationAdminPath,
  isProtectedOrganizationRoute,
  organizationEndpoints,
} from '@/modules/_core/organization/organization.routes';
export type {
  OrganizationRouteConfig,
  OrganizationEndpointMetadata,
} from '@/modules/_core/organization/organization.routes';

// -----------------------------------------------------------------------------
// Types
// -----------------------------------------------------------------------------

// Core entity types
export type {
  Organization,
  OrganizationWithRelations,
} from '@/modules/_core/organization/organization.types';

// Settings types
export type {
  OrganizationSettings,
  BusinessSettings,
  LocalizationSettings,
  FeatureSettings,
  NotificationSettings,
  BrandingSettings,
  AddressInfo,
  OperatingHours,
  DayHours,
} from '@/modules/_core/organization/organization.types';

// Request/Response types
export type {
  CreateOrganizationRequest,
  CreateOrganizationResponse,
  UpdateOrganizationRequest,
  UpdateOrganizationResponse,
  UpdateSettingsRequest,
  UpdateSettingsResponse,
  ChangeStatusRequest,
  ChangeStatusResponse,
  OrganizationSummary,
} from '@/modules/_core/organization/organization.types';

// Query/Filter types
export type {
  OrganizationListFilters,
  OrganizationListParams,
} from '@/modules/_core/organization/organization.types';

// Event types
export type {
  OrganizationCreatedEvent,
  OrganizationUpdatedEvent,
  OrganizationDeletedEvent,
  OrganizationSettingsUpdatedEvent,
  OrganizationStatusChangedEvent,
} from '@/modules/_core/organization/organization.types';

// Hook context types
export type {
  BeforeCreateContext,
  AfterCreateContext,
  BeforeUpdateContext,
  AfterUpdateContext,
} from '@/modules/_core/organization/organization.types';

// Module settings types
export type { OrganizationModuleSettings } from '@/modules/_core/organization/organization.types';

// Type guards
export {
  isOrganization,
  isOrganizationSettings,
} from '@/modules/_core/organization/organization.types';

// -----------------------------------------------------------------------------
// Schemas (Zod validation)
// -----------------------------------------------------------------------------

export {
  // Base schemas
  organizationNameSchema,
  organizationSlugSchema,
  emailSchema,
  phoneSchema,
  urlSchema,
  colorHexSchema,

  // Settings schemas
  addressSchema,
  dayHoursSchema,
  operatingHoursSchema,
  businessSettingsSchema,
  localizationSettingsSchema,
  featureSettingsSchema,
  notificationSettingsSchema,
  brandingSettingsSchema,
  organizationSettingsSchema,

  // CRUD schemas
  createOrganizationSchema,
  updateOrganizationSchema,
  updateSettingsSchema,
  changeStatusSchema,

  // Query schemas
  organizationListQuerySchema,
  organizationIdSchema,

  // Response schemas
  organizationResponseSchema,
  organizationSummarySchema,

  // Module settings schema
  organizationModuleSettingsSchema,

  // Utility functions
  generateSlug,
  generateUniqueSlug,
  mergeSettings,
} from '@/modules/_core/organization/organization.schema';

export type {
  CreateOrganizationInput,
  UpdateOrganizationInput,
  UpdateSettingsInput,
  ChangeStatusInput,
  OrganizationListQueryInput,
  OrganizationIdInput,
  OrganizationModuleSettingsInput,
} from '@/modules/_core/organization/organization.schema';
